import{_ as e,o as a,c as t,d}from"./app.af3b57da.js";const r={},h=d('<h1 id="\u5176\u4ED6\u6E38\u620F" tabindex="-1"><a class="header-anchor" href="#\u5176\u4ED6\u6E38\u620F" aria-hidden="true">#</a> \u5176\u4ED6\u6E38\u620F</h1><h2 id="uno\u6269\u5C55\u89C4\u52195-0-1" tabindex="-1"><a class="header-anchor" href="#uno\u6269\u5C55\u89C4\u52195-0-1" aria-hidden="true">#</a> UNO\u6269\u5C55\u89C4\u52195.0.1</h2><p>\u8FD9\u662F\u4E00\u4E2A\u9AD8\u5EA6\u6269\u5C55\u7684\u7EBF\u4E0B\u684C\u6E38\u3002\u7531\u4E8E\u8FED\u4EE3\u6B21\u6570\u8F83\u591A\uFF0C\u5177\u6709\u8F83\u9AD8\u53EF\u73A9\u6027\u3002\u4F60\u53EF\u4EE5\u81EA\u5236\u4E00\u5957\u724C\u8FDB\u884C\u6E38\u73A9\u3002</p><table><thead><tr><th style="text-align:center;">\u724C\u540D</th><th style="text-align:center;">\u6570\u91CF</th></tr></thead><tbody><tr><td style="text-align:center;">\u6570\u5B57\u724C\uFF080-9\uFF09</td><td style="text-align:center;"><code>0</code>\u6BCF\u82721\u5F20\uFF0C\u5176\u4ED6\u6570\u5B57\u6BCF\u82722\u5F20</td></tr><tr><td style="text-align:center;">\u7981</td><td style="text-align:center;">\u6BCF\u82722\u5F20</td></tr><tr><td style="text-align:center;">\u8F6C</td><td style="text-align:center;">\u6BCF\u82722\u5F20</td></tr><tr><td style="text-align:center;">+2</td><td style="text-align:center;">\u6BCF\u82722\u5F20</td></tr><tr><td style="text-align:center;">\u65E0\u9650(\u221E)</td><td style="text-align:center;">\u6BCF\u82721\u5F20</td></tr><tr><td style="text-align:center;">\u4F20\u9012</td><td style="text-align:center;">\u6BCF\u82722\u5F20\uFF0C\u5206<code>&lt;=4</code>\u4E0E<code>&gt;=5</code>\u4E24\u79CD</td></tr><tr><td style="text-align:center;">\u795E\u624B</td><td style="text-align:center;">\u6BCF\u82721\u5F20</td></tr><tr><td style="text-align:center;">\u5939\u5B50</td><td style="text-align:center;">\u6BCF\u82721\u5F20</td></tr><tr><td style="text-align:center;">\u5956\u52B1</td><td style="text-align:center;">\u6BCF\u82721\u5F20</td></tr><tr><td style="text-align:center;">\u6539\u8272</td><td style="text-align:center;">4</td></tr><tr><td style="text-align:center;">+4</td><td style="text-align:center;">4</td></tr><tr><td style="text-align:center;">\u53CD\u5F39</td><td style="text-align:center;">2</td></tr><tr><td style="text-align:center;">pass</td><td style="text-align:center;">2</td></tr><tr><td style="text-align:center;">\u51B3\u6597</td><td style="text-align:center;">\u989C\u8272\u51B3\u65971\u5F20\uFF0C\u70B9\u6570\u51B3\u65971\u5F20</td></tr><tr><td style="text-align:center;">\u5929\u9009\u4E4B\u5B50</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">\u70B8\u5F39</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">\u7F34\u68B0</td><td style="text-align:center;">2</td></tr><tr><td style="text-align:center;">\u624B\u69B4\u5F39</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">\u7D27\u7B8D\u5492</td><td style="text-align:center;">2</td></tr><tr><td style="text-align:center;">\u590D\u6D3B</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">C4</td><td style="text-align:center;">1</td></tr><tr><td style="text-align:center;">\u62AC\u6760</td><td style="text-align:center;">1</td></tr></tbody></table><h3 id="\u57FA\u672C\u89C4\u5219" tabindex="-1"><a class="header-anchor" href="#\u57FA\u672C\u89C4\u5219" aria-hidden="true">#</a> \u57FA\u672C\u89C4\u5219</h3><p>UNO\u6269\u5C55\u89C4\u5219\u7EE7\u627F\u81EAUNO\uFF0C\u5E95\u5C42\u89C4\u5219\u81EA\u7136\u4FBF\u662FUNO\u89C4\u5219\u3002</p><p>\u4EE5\u4E0B\u4E3A\u5BF9\u89C4\u5219\u7684\u4E25\u8C28\u6027\u9648\u8FF0\uFF0C\u5F53\u6253\u724C\u8FC7\u7A0B\u4E2D\u9047\u5230\u7EA0\u7EB7\u65F6\u8BF7\u4EE5\u8BE5\u4E25\u8C28\u6027\u89C4\u5219\u4E3A\u51C6\u3002\u5BF9\u4E8E\u60F3\u8981\u5FEB\u901F\u4E0A\u624B\u7684\u65B0\u73A9\u5BB6\uFF0C\u5EFA\u8BAE <strong>\u5728\u9605\u8BFB<a href="#%E5%9F%BA%E6%9C%AC%E8%A7%84%E5%88%99">\u57FA\u672C\u89C4\u5219</a>\u4E0E<a href="#%E5%BC%80%E5%B1%80%E8%A7%84%E5%88%99">\u5F00\u5C40\u89C4\u5219</a>\u540E\uFF0C<a href="#%E7%B2%BE%E7%AE%80%E8%A7%84%E5%88%99">\u8DF3\u8F6C\u5230\u7CBE\u7B80\u89C4\u5219</a>\u8FDB\u884C\u9605\u8BFB</strong>\u3002</p><p>\u9664\u4E86\u6570\u5B57\u724C\u4EE5\u5916\u7684\u724C\u5747\u79F0\u4F5C\u529F\u80FD\u724C\u3002\u9ED1\u724C\u6307\u4E0A\u8868\u4E2D\u4E0D\u5E26\u6709<code>\u6BCF\u8272x\u5F20</code>\u5B57\u6837\u7684\u724C\u3002</p><p>\u6211\u4EEC\u5C06 <strong>\u201C\u5F53\u524D\u724C\u201D\u79F0\u4E3A<code>last</code>\u3002</strong> \u4F60\u6253\u51FA\u7684\u724C<strong>\u82E5\u975E\u9ED1\u724C</strong>\uFF0C\u5219\u9700\u4E0E<code>last</code><strong>\u6570\u5B57/\u529F\u80FD\u76F8\u540C</strong>\u6216<strong>\u989C\u8272\u76F8\u540C</strong>\u3002\u800C\u4E0D\u8BBA\u4F60\u6253\u51FA\u4EC0\u4E48\u724C\uFF0C\u90FD\u9700\u8981\u6EE1\u8DB3\u8BE5\u724C\u7684\u6253\u51FA\u6761\u4EF6\u3002\u9664<code>\u6539\u8272</code> <code>+4</code>\u5916\u7684\u6240\u6709\u9ED1\u724C\u6253\u51FA\u65F6\u4E0D\u4F1A<strong>\u76F4\u63A5</strong>\u6539\u53D8<code>last</code>\u3002\u975E\u9ED1\u724C\u6253\u51FA\u540E\u5C06\u4F1A\u66FF\u6362<code>last</code>\u3002</p><p>\u4F60\u7684\u6BCF\u4E2A\u56DE\u5408\u53EF\u5206\u4E3A\u4E09\u4E2A\u9636\u6BB5\uFF1A</p><ol><li>\u5224\u5B9A\u9636\u6BB5\uFF1A\u5904\u7406\u4F60\u8EAB\u4E0A\u7684\u5F53\u524D\uFF08\u6FC0\u6D3B\u6027\uFF09\u6548\u679C\u3002</li><li>\u6478\u724C\u9636\u6BB5\uFF1A\u6478<strong>\u4E00\u5F20</strong>\u724C\u3002</li><li>\u51FA\u724C\u9636\u6BB5\uFF1A\u6309\u7167\u51FA\u724C\u89C4\u5219\u51FA\u4E00\u5F20\u724C <em>\uFF08\u67D0\u4E9B\u529F\u80FD\u724C\u53EF\u4EE5\u8BA9\u4F60\u51FA\u66F4\u591A\u724C\uFF09</em>\u3002</li></ol><p>\u5224\u5B9A\u9636\u6BB5\u662F\u5F3A\u5236\u6027\u7684\uFF0C\u800C\u6478\u724C\u9636\u6BB5\u4E0E\u51FA\u724C\u9636\u6BB5\u4F60\u53EF\u9009\u62E9\u5176\u4E00\uFF0C\u6216\u4E24\u4E2A\u90FD\u9009\uFF0C\u4F46\u4E0D\u53EF\u4E0D\u9009\u3002<em>\uFF08\u8BF4\u4EBA\u8BDD\uFF1A\u6CA1\u724C\u53EF\u51FA\u5C31\u6478\uFF09</em></p><p>\u4F60\u9700\u8981\u5728\u4F60\u7684\u624B\u724C<text style="color:red;">\u4ECE\u591A\u4E8E\u4E00\u5F20\u53D8\u4E3A\u53EA\u5269\u4E00\u5F20</text>\u540E\u558A\u201CUNO!\u201D\u3002\u82E5\u88AB\u4EFB\u610F\u73A9\u5BB6\u6307\u51FA\u6CA1\u558A\u5219\u9700\u6478\u4E24\u5F20\u3002\u4F60\u7684\u624B\u724C\u5728\u8131\u79BB\u80A2\u4F53\u63A5\u89E6\u65F6\u624D\u89C6\u4E3A\u5931\u53BB\u3002</p><p><strong><text style="color:red;">\u6240\u6709\u529F\u80FD\u724C\u7684\u529F\u80FD\u90FD\u53EF\u88AB\u89C6\u4E3A\u6548\u679C\u3002</text></strong></p><h4 id="\u6548\u679C\u5206\u7C7B" tabindex="-1"><a class="header-anchor" href="#\u6548\u679C\u5206\u7C7B" aria-hidden="true">#</a> \u6548\u679C\u5206\u7C7B</h4><h5 id="\u5373\u65F6\u6027\u6548\u679C" tabindex="-1"><a class="header-anchor" href="#\u5373\u65F6\u6027\u6548\u679C" aria-hidden="true">#</a> \u5373\u65F6\u6027\u6548\u679C</h5><p>\u4F60\uFF08\u6216\u6E38\u620F\uFF09\u9700\u8981\u7ACB\u523B\u5BF9\u5B83\u4F5C\u51FA\u56DE\u5E94\u3002</p><h5 id="\u6301\u7EED\u6027\u6548\u679C" tabindex="-1"><a class="header-anchor" href="#\u6301\u7EED\u6027\u6548\u679C" aria-hidden="true">#</a> \u6301\u7EED\u6027\u6548\u679C</h5><p>\u6301\u7EED\u4E00\u6BB5\u65F6\u95F4\uFF0C\u6709\u660E\u786E\u7684\u7ED3\u675F\u6761\u4EF6\u3002</p><h5 id="\u6FC0\u6D3B\u6027\u6548\u679C" tabindex="-1"><a class="header-anchor" href="#\u6FC0\u6D3B\u6027\u6548\u679C" aria-hidden="true">#</a> \u6FC0\u6D3B\u6027\u6548\u679C</h5><p>\u4F60\u9700\u8981\u5728\u4F60\u7684\u5224\u5B9A\u9636\u6BB5\u4F5C\u51FA\u56DE\u5E94\u3002</p><h5 id="aoe\u6548\u679C" tabindex="-1"><a class="header-anchor" href="#aoe\u6548\u679C" aria-hidden="true">#</a> AOE\u6548\u679C</h5><p>\u5BF9\u5168\u5C40\u65BD\u52A0\u6548\u679C\uFF0C\u6682\u65F6\u505C\u6B62\u6B63\u5E38\u6E38\u620F\uFF0C\u76F4\u5230\u6548\u679C\u7ED3\u675F\uFF1B\u4F60\u65E0\u9700\u7ACB\u523B\u56DE\u5E94\uFF0C\u800C\u5E94\u5728\u6548\u679C\u6307\u5B9A\u5230\u4F60\u540E\u56DE\u5E94\u3002</p><h5 id="\u81EA\u751F\u6548\u6548\u679C" tabindex="-1"><a class="header-anchor" href="#\u81EA\u751F\u6548\u6548\u679C" aria-hidden="true">#</a> \u81EA\u751F\u6548\u6548\u679C</h5><p>\u4E3A\u724C\u672C\u8EAB\u6DFB\u52A0\u6548\u679C\u3002</p><p>\u80DC\u5229\u6761\u4EF6\u4E3A<strong>\u6253\u5B8C\u6240\u6709\u624B\u724C\u3001\u8EAB\u4E0A\u4E0D\u9644\u5E26\u4EFB\u4F55\u6548\u679C\u3001\u4E14\u4E0D\u5B58\u5728\u88AB\u9644\u52A0\u6548\u679C\u7684\u53EF\u80FD\u6027</strong>\u3002\u4F8B\u5982\uFF1A\u4F60\u6253\u51FA\u4E86\u4F60\u6700\u540E\u7684\u624B\u724C\uFF08\u4E00\u5F20+4\u724C\uFF09\uFF0C\u4F46\u5728\u8FD9\u5F20+4\u751F\u6548\u524D\u4F60\u4ECD\u672A\u80DC\u5229\uFF0C\u56E0\u4E3A\u5B83\u6709\u4F20\u9012\u5230\u4F60\u8EAB\u4E0A\u7684\u53EF\u80FD\u6027\u3002\u540C\u7406\uFF0C\u82E5\u4F60\u6700\u540E\u7684\u624B\u724C\u662F\u795E\u624B\u3001\u5939\u5B50\u3001\u624B\u69B4\u5F39<strong>\u7B49\u7B49</strong>\uFF0C\u5728\u6548\u679C\u7ED3\u7B97\u5B8C\u6210\u524D\uFF0C\u90FD\u4E0D\u53EF\u7B97\u4F5C\u80DC\u5229\u3002</p><h3 id="\u5F00\u5C40\u89C4\u5219" tabindex="-1"><a class="header-anchor" href="#\u5F00\u5C40\u89C4\u5219" aria-hidden="true">#</a> \u5F00\u5C40\u89C4\u5219</h3><p>\u6E38\u620F\u5EFA\u8BAE\u91C7\u7528\u79EF\u5206\u5236\uFF08\u5F53\u7136\u4F60\u4E5F\u53EF\u4EE5\u4E0D\u7528\uFF09\u3002\u6BCF\u4F4D\u80DC\u5229\u7684\u73A9\u5BB6\u83B7\u5F97x\u5206\uFF0Cx\u4E3A\u5F53\u524D\u573A\u4E0A\u5B58\u6D3B\u7684\u4EBA\u6570\u3002\u590D\u6D3B\u8D5B\u7684\u73A9\u5BB6\u82E5\u80DC\u5229\u5219\u540C\u6837\u8BA1\u5206\u3002</p><p>\u521D\u59CB\u624B\u724C\u6570\u53EF\u4EE5\u9009\u75285,7,9\u7B49\u6570\u5B57\uFF08\u6839\u636E\u73A9\u5BB6\u6570\u51B3\u5B9A\uFF09\u3002\u5F53\u624B\u724C\u6570\u8D85\u8FC7<code>\u521D\u59CB\u624B\u724C\u6570*3</code>\u65F6\uFF0C\u73A9\u5BB6\u5C06\u4E0D\u5141\u8BB8\u4ECE\u724C\u5806\u83B7\u5F97\u624B\u724C\u3002</p><p>\u6BCF\u4E2A\u73A9\u5BB6\u6478\u521D\u59CB\u624B\u724C\u540E\u9700\u8981\u51B3\u5B9A\u7B2C\u4E00\u51FA\u724C\u4EBA\uFF08\u5EFA\u8BAE\u4F7F\u7528\u62FC\u70B9\u3001\u77F3\u5934\u526A\u5200\u5E03\u3001\u4E0A\u4E00\u5C40\u6700\u5FEB\u80DC\u5229\u8005\u76F4\u63A5\u62C5\u4EFB\u7B49\u65B9\u5F0F\u51B3\u5B9A\uFF09\u3002\u7B2C\u4E00\u51FA\u724C\u4EBA\u53EF\u4EE5\u81EA\u7531\u6307\u5B9A\u987A\u5E8F\uFF08\u987A\u9006\u65F6\u9488\uFF09\uFF0C\u5E76\u7FFB\u5F00\u724C\u5806\u7684\u4E00\u5F20\u975E\u9ED1\u724C\u4F5C\u4E3A<code>last</code>\u3002\u7136\u540E\u6E38\u620F\u7531\u7B2C\u4E00\u51FA\u724C\u4EBA\u5F00\u59CB\u51FA\u724C\u3002</p><h3 id="\u5E38\u89C1\u6548\u679C" tabindex="-1"><a class="header-anchor" href="#\u5E38\u89C1\u6548\u679C" aria-hidden="true">#</a> \u5E38\u89C1\u6548\u679C</h3><h4 id="\u52A0\u724C\u6548\u679C" tabindex="-1"><a class="header-anchor" href="#\u52A0\u724C\u6548\u679C" aria-hidden="true">#</a> \u52A0\u724C\u6548\u679C</h4><p>\u5C5E\u4E8E<a href="#%E6%BF%80%E6%B4%BB%E6%80%A7%E6%95%88%E6%9E%9C">\u6FC0\u6D3B\u6027\u6548\u679C</a>\uFF0C\u62E5\u6709\u4E24\u4E2A\u53D8\u91CF\uFF1A<code>\u5F53\u524D\u52A0\u724C\u6570</code>\u4E0E<code>\u6700\u5927\u52A0\u724C\u503C</code>\u3002<code>\u5F53\u524D\u52A0\u724C\u6570</code>\u4EE3\u8868\u82E5\u4F60\u63A5\u53D7\u52A0\u724C\u540E\u9700\u8981\u6478\u724C\u7684\u6570\u91CF\u3002<code>\u6700\u5927\u52A0\u724C\u503C</code>\u4EE3\u8868\u53EA\u6709\u5927\u4E8E\u7B49\u4E8E\u8BE5\u503C\u7684\u52A0\u724C\u6548\u679C\u624D\u53EF\u7EE7\u7EED\u53E0\u52A0\uFF08\u8BF4\u4EBA\u8BDD\uFF1A+2\u4E0D\u80FD\u53E0\u52A0\u5728+4\u4E0A\u9762\uFF09\u3002<code>\u5F53\u524D\u52A0\u724C\u6570</code>\u53EF\u53E0\u52A0\u3002<code>\u6700\u5927\u52A0\u724C\u503C</code>\u53D6\u53E0\u52A0\u8FC7\u7A0B\u4E2D\u6700\u5927\u503C\uFF082\u62164\uFF09\u3002</p><p>\u73A9\u5BB6\u5224\u5B9A\u9636\u6BB5\u9009\u62E9\u63A5\u53D7\u4E0E\u4E0D\u63A5\u53D7\u52A0\u724C\u6548\u679C\uFF0C\uFF08\u4E0D\u7BA1\u505A\u4F55\u9009\u62E9\u90FD\uFF09\u8DF3\u8FC7\u4ED6\u7684\u56DE\u5408\u3002</p><ul><li>\u63A5\u53D7\u52A0\u724C\uFF1A\u6478<code>\u5F53\u524D\u52A0\u724C\u6570</code>\u6570\u91CF\u7684\u724C\u3002\u6548\u679C\u7ED3\u675F\u3002</li><li>\u4E0D\u63A5\u53D7\u52A0\u724C\uFF1A\u65BD\u52A0\u65B0\u7684\u52A0\u724C\u6548\u679C\uFF08\u6548\u679C\u9700\u4E0D\u5C0F\u4E8E\u5F53\u524D<code>\u6700\u5927\u52A0\u724C\u503C</code>\uFF09\uFF0C\u5C06\u52A0\u724C\u6548\u679C\u53E0\u52A0\u540E\u7EE7\u7EED\u65BD\u52A0\u7ED9\u4E0B\u5BB6\u3002</li></ul><h4 id="\u8F6C\u79FB\u724C\u6548\u679C" tabindex="-1"><a class="header-anchor" href="#\u8F6C\u79FB\u724C\u6548\u679C" aria-hidden="true">#</a> \u8F6C\u79FB\u724C\u6548\u679C</h4><p>\u5C5E\u4E8E<a href="#%E6%BF%80%E6%B4%BB%E6%80%A7%E6%95%88%E6%9E%9C">\u6FC0\u6D3B\u6027\u6548\u679C</a>\u3002\u6548\u679C\u65BD\u52A0\u8005\u53EF\u4E3A\u6B64\u6548\u679C\u9644\u52A00/1/2\u5F20\u624B\u724C\uFF08\u8BE5\u9644\u52A0\u724C\u53EF\u53E0\u52A0\uFF09\u3002\u7136\u540E\u5C06\u6B64\u6548\u679C\u4E0E\u9644\u52A0\u724C\u4F20\u7ED9\u4E0B\u5BB6\u3002\u9644\u52A0\u724C\u5728\u4F20\u9012\u8FC7\u7A0B\u4E2D\u5E94\u80CC\u9762\u671D\u4E0A\uFF0C\u5728\u4E0B\u5BB6\u672A\u8868\u660E\u63A5\u53D7\u4E0E\u5426\u524D\u4E0D\u5E94\u6CC4\u9732\u3002\u82E5\u4E0B\u5BB6\u7FFB\u770B\u9644\u52A0\u724C\u5219\u9ED8\u8BA4\u4E3A\u63A5\u53D7\u6548\u679C\u3002</p><p>\u73A9\u5BB6\u5224\u5B9A\u9636\u6BB5\u9009\u62E9\u63A5\u53D7\u4E0E\u4E0D\u63A5\u53D7\u8F6C\u79FB\u724C\u6548\u679C\u3002</p><ul><li>\u63A5\u53D7\u8F6C\u79FB\u724C\uFF1A\u83B7\u5F97\u6548\u679C\u4E0A\u7684\u9644\u52A0\u724C\uFF0C\u5E76\u83B7\u5F97 <em>\u7981\u9522\u6548\u679C\uFF08<a href="#%E6%8C%81%E7%BB%AD%E6%80%A7%E6%95%88%E6%9E%9C">\u6301\u7EED\u6027\u6548\u679C</a>\uFF09\uFF1A\u672C\u56DE\u5408\u5185\u4F60\u65E0\u6CD5\u6253\u51FA\u8F6C\u79FB\u724C\u76F4\u5230\u56DE\u5408\u7ED3\u675F\u89E3\u9664\u3002</em> \u8F6C\u79FB\u724C\u6548\u679C\u7ED3\u675F\u3002</li><li>\u4E0D\u63A5\u53D7\u8F6C\u79FB\u724C\uFF1A\u6253\u51FA\u540C\u7C7B\u578B\u8F6C\u79FB\u724C\uFF0C\u7ED9\u8BE5\u6548\u679C\u9644\u52A00/1/2\u5F20\u624B\u724C\uFF0C\u5C06\u6548\u679C\u53E0\u52A0\u540E\u65BD\u52A0\u7ED9\u4E0B\u5BB6\u5E76\u8DF3\u8FC7\u81EA\u5DF1\u7684\u56DE\u5408\u3002\u8FC7\u7A0B\u4E2D\u4E0D\u7FFB\u770B\u9644\u52A0\u724C\u3002</li></ul><h4 id="\u7729\u6655\u6548\u679C" tabindex="-1"><a class="header-anchor" href="#\u7729\u6655\u6548\u679C" aria-hidden="true">#</a> \u7729\u6655\u6548\u679C</h4><p>\u5C5E\u4E8E<a href="#%E6%BF%80%E6%B4%BB%E6%80%A7%E6%95%88%E6%9E%9C">\u6FC0\u6D3B\u6027\u6548\u679C</a>\u3002</p><p>\u73A9\u5BB6\u7ACB\u523B\u8DF3\u8FC7\u81EA\u5DF1\u7684\u8BE5\u56DE\u5408\u3002\u6548\u679C\u7ED3\u675F\u3002</p><h4 id="\u865A\u5F31\u6548\u679C" tabindex="-1"><a class="header-anchor" href="#\u865A\u5F31\u6548\u679C" aria-hidden="true">#</a> \u865A\u5F31\u6548\u679C</h4><p>\u5C5E\u4E8E<a href="#%E6%8C%81%E7%BB%AD%E6%80%A7%E6%95%88%E6%9E%9C">\u6301\u7EED\u6027\u6548\u679C</a>\u3002</p><p>\u4E0D\u53EF\u6253\u51FA<code>pass</code>\u3001<code>\u53CD\u5F39</code>\u3001<code>\u4F20\u9012</code>\u76F4\u5230\u6548\u679C\u89E3\u9664\u3002</p><p>\u89E3\u9664\u6761\u4EF6\uFF1A\u4F60\u7684\u5224\u5B9A\u9636\u6BB5\u7ED3\u675F\u540E\u81EA\u52A8\u89E3\u9664\u3002</p><h3 id="\u7981" tabindex="-1"><a class="header-anchor" href="#\u7981" aria-hidden="true">#</a> \u7981</h3><p><a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF1A\u7ACB\u523B\u8DF3\u8F6C\u5230\u4F7F\u7528\u8005\u4E0B\u4E24\u5BB6\uFF0C\u5F00\u59CB\u8BE5\u73A9\u5BB6\u7684\u56DE\u5408\u3002</p><div class="custom-container tip"><p class="custom-container-title">\u63D0\u793A</p><p><em><strong>\u7981</strong></em> \u724C\u62E5\u6709\u529F\u80FD\u724C\u4E2D\u6700\u9AD8\u7684\u4F18\u5148\u7EA7\u3002</p></div><h3 id="\u8F6C" tabindex="-1"><a class="header-anchor" href="#\u8F6C" aria-hidden="true">#</a> \u8F6C</h3><p><a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF1A\u9006\u8F6C\u51FA\u724C\u987A\u5E8F\u3002</p><h3 id="_2" tabindex="-1"><a class="header-anchor" href="#_2" aria-hidden="true">#</a> +2</h3><p><a href="#%E6%BF%80%E6%B4%BB%E6%80%A7%E6%95%88%E6%9E%9C">\u6FC0\u6D3B\u6027\u6548\u679C</a>\uFF1A\u5BF9\u4E0B\u5BB6\u65BD\u52A0<a href="#%E5%8A%A0%E7%89%8C%E6%95%88%E6%9E%9C">\u52A0\u724C\u6548\u679C</a>\uFF1A<code>\u5F53\u524D\u52A0\u724C\u6570</code> = 2 , <code>\u6700\u5927\u52A0\u724C\u503C</code> = 2\u3002</p><h3 id="_4" tabindex="-1"><a class="header-anchor" href="#_4" aria-hidden="true">#</a> +4</h3><p><a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF1A\u66F4\u6539<code>last</code>\u7684\u989C\u8272\u4E3A\u6307\u5B9A\u989C\u8272\uFF08\u6570\u5B57/\u529F\u80FD\u89C6\u4E3A\u65E0\u7C7B\u578B\uFF09\u3002</p><p><a href="#%E6%BF%80%E6%B4%BB%E6%80%A7%E6%95%88%E6%9E%9C">\u6FC0\u6D3B\u6027\u6548\u679C</a>\uFF1A\u5BF9\u4E0B\u5BB6\u65BD\u52A0<a href="#%E5%8A%A0%E7%89%8C%E6%95%88%E6%9E%9C">\u52A0\u724C\u6548\u679C</a>\uFF1A<code>\u5F53\u524D\u52A0\u724C\u6570</code> = 4 , <code>\u6700\u5927\u52A0\u724C\u503C</code> = 4\u3002</p><h3 id="\u6539\u8272" tabindex="-1"><a class="header-anchor" href="#\u6539\u8272" aria-hidden="true">#</a> \u6539\u8272</h3><p><a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF1A\u66F4\u6539<code>last</code>\u7684\u989C\u8272\u4E3A\u6307\u5B9A\u989C\u8272\uFF08\u6570\u5B57/\u529F\u80FD\u89C6\u4E3A\u65E0\u7C7B\u578B\uFF09\u3002</p><h3 id="\u65E0\u9650" tabindex="-1"><a class="header-anchor" href="#\u65E0\u9650" aria-hidden="true">#</a> \u65E0\u9650</h3><p><a href="#%E8%87%AA%E7%94%9F%E6%95%88%E6%95%88%E6%9E%9C">\u81EA\u751F\u6548\u6548\u679C</a>\uFF1A\u53EF\u4EE5\u6307\u5B9A\u4E3A\u4EFB\u610F\u6570\u5B57\u4F7F\u7528\uFF08\u4E0D\u6539\u53D8\u989C\u8272\uFF09\u3002\u4F46\u4E0D\u53EF\u5728<a href="#%E8%B5%8C%E6%80%AA">\u8D4C\u602A\uFF08\u5DF2\u5F03\u7528\uFF09</a>\u7684AOE\u6548\u679C\u4E2D\u4F7F\u7528\u3002</p><h3 id="\u4F20\u9012" tabindex="-1"><a class="header-anchor" href="#\u4F20\u9012" aria-hidden="true">#</a> \u4F20\u9012</h3><p><em>\u5206\u4E3A<code>&lt;=4</code>\u4E0E<code>&gt;=5</code>\u4E24\u79CD\uFF0C\u5E94\u89C6\u4F5C\u4E0D\u540C\u7C7B\u578B\u724C\u3002</em></p><p>\u6253\u51FA\u6761\u4EF6\uFF1A<code>last</code>\u540C\u65F6\u6EE1\u8DB3\u989C\u8272\u6761\u4EF6\u4E0E\u6570\u5B57\u6761\u4EF6\uFF0C\u6216<code>last</code>\u4E3A\u540C\u7C7B\u578B\u724C\u3002</p><p><a href="#%E6%BF%80%E6%B4%BB%E6%80%A7%E6%95%88%E6%9E%9C">\u6FC0\u6D3B\u6027\u6548\u679C</a>\uFF1A\u4E3A\u4E0B\u5BB6\u9644\u52A0<a href="#%E8%BD%AC%E7%A7%BB%E7%89%8C%E6%95%88%E6%9E%9C">\u8F6C\u79FB\u724C\u6548\u679C</a>\u3002</p><h3 id="\u795E\u624B" tabindex="-1"><a class="header-anchor" href="#\u795E\u624B" aria-hidden="true">#</a> \u795E\u624B</h3><p><a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF1A\u4E0E\u4E0B\u5BB6\u4E92\u6362\u624B\u724C\u3002\u8BE5\u6548\u679C\u4F18\u5148\u7EA7\u4EC5\u6B21\u4E8E<a href="#%E7%A6%81">\u7981</a>\uFF0C\u4E0D\u53EF\u88AB\u8F6C\u79FB\u3002</p><h3 id="\u5939\u5B50" tabindex="-1"><a class="header-anchor" href="#\u5939\u5B50" aria-hidden="true">#</a> \u5939\u5B50</h3><p><a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF1A\u62BD\u53D6\u4E0B\u5BB6\u4E24\u5F20\u624B\u724C\uFF0C\u82E5\u4E0D\u8DB3\u4E24\u5F20\u5219\u62BD\u53D6\u5168\u90E8\u3002</p><h3 id="\u53CD\u5F39" tabindex="-1"><a class="header-anchor" href="#\u53CD\u5F39" aria-hidden="true">#</a> \u53CD\u5F39</h3><p><a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF1A\u5148\u65BD\u52A0<a href="#%E8%BD%AC"><code>\u8F6C</code>\u6548\u679C</a>\u518D\u65BD\u52A0<a href="#pass"><code>pass</code>\u6548\u679C</a>\u3002</p><h3 id="pass" tabindex="-1"><a class="header-anchor" href="#pass" aria-hidden="true">#</a> pass</h3><p><a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF1A\u5C06\u81EA\u8EAB<a href="#%E5%8A%A0%E7%89%8C%E6%95%88%E6%9E%9C">\u52A0\u724C\u6548\u679C</a>\u4E0E<a href="#%E8%BD%AC%E7%A7%BB%E7%89%8C%E6%95%88%E6%9E%9C">\u8F6C\u79FB\u724C\u6548\u679C</a>\u8F6C\u79FB\u7ED9\u4E0B\u5BB6\u3002\uFF08\u82E5\u65E0\u6548\u679C\u5219\u5F53\u4F5C\u767D\u724C\u6253\uFF09</p><h3 id="\u51B3\u6597" tabindex="-1"><a class="header-anchor" href="#\u51B3\u6597" aria-hidden="true">#</a> \u51B3\u6597</h3><p><em>\u5206\u4E3A<code>\u989C\u8272\u51B3\u6597</code>\u4E0E<code>\u70B9\u6570\u51B3\u6597</code>\u4E24\u79CD\u3002</em></p><p><a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF1A\u6307\u5B9A\u4EFB\u610F\u4E00\u540D\u73A9\u5BB6\u8FDB\u884C\u51B3\u6597\u3002\u80DC\u8005\u5F03\u4E24\u5F20\u724C\uFF08\u4E0D\u8DB3\u5219\u5168\u5F03\uFF09\uFF0C\u8D25\u8005\u52A0\u56DB\u5F20\u724C\uFF0C\u5E73\u5C40\u7B97\u7686\u8D25\u3002</p><ul><li>\u989C\u8272\u51B3\u6597\u89C4\u5219\uFF1A<details><summary>\u70B9\u51FB\u5C55\u5F00</summary><p>\u53D1\u8D77\u4EBA\u9009\u62E95\u4E2A\u989C\u8272\uFF08\u5305\u62EC\u9ED1\u8272\uFF09\u4E2D\u7684\u4E00\u4E2A\uFF0C\u63A5\u53D7\u8005\u9009\u62E9\u4E0D\u540C\u989C\u8272\uFF0C\u7136\u540E\u53D1\u8D77\u4EBA\u4ECE\u724C\u5806\u7FFB\u8D77\u4E00\u5F20\u724C\u5E76\u516C\u793A\uFF0C\u731C\u5BF9\u80DC\u5229\uFF0C\u731C\u9519\u5931\u8D25\u3002\uFF08\u9009\u62E9\u989C\u8272\u7684\u987A\u5E8F\u53EF\u7531\u53D1\u8D77\u4EBA\u51B3\u5B9A\u3002\uFF09</p></details></li><li>\u70B9\u6570\u51B3\u6597\u89C4\u5219\uFF1A<details><summary>\u70B9\u51FB\u5C55\u5F00</summary><p>\u4E24\u4EBA\u5404\u4ECE\u724C\u5806\u4E2D\u7FFB\u4E00\u5F20\u724C\u62FC\u70B9\uFF0C\u70B9\u6570\u5927\u7684\u83B7\u80DC\u3002</p></details></li></ul><h3 id="\u5929\u9009\u4E4B\u5B50" tabindex="-1"><a class="header-anchor" href="#\u5929\u9009\u4E4B\u5B50" aria-hidden="true">#</a> \u5929\u9009\u4E4B\u5B50</h3><p><a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF1A\u53EA\u4FDD\u7559\u4E00\u5F20\u6570\u5B57\u724C\uFF0C\u5F03\u6389\u5176\u4ED6\u6240\u6709\u724C\u3002\u82E5\u65E0\u6570\u5B57\u724C\u5219\u5168\u5F03\u3002</p><h3 id="\u70B8\u5F39" tabindex="-1"><a class="header-anchor" href="#\u70B8\u5F39" aria-hidden="true">#</a> \u70B8\u5F39</h3><p><a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF1A\u4EE5\u53D1\u8D77\u8005\u4E3A\u4E2D\u5FC3\uFF0C\u53D1\u8D77\u8005\u6478x\u5F20\u724C\uFF0C\u4E24\u4FA7\u73A9\u5BB6\u89C6\u8DDD\u79BB\u4F9D\u6B21\u6478x-1\u5F20\u724C\uFF0Cx-2\u5F20\u724C...x\u4E3A\u5F53\u524D\u573A\u4E0A\u5B58\u6D3B\u73A9\u5BB6\u6570\u3002</p><h3 id="\u7F34\u68B0" tabindex="-1"><a class="header-anchor" href="#\u7F34\u68B0" aria-hidden="true">#</a> \u7F34\u68B0</h3><p><a href="#%E6%BF%80%E6%B4%BB%E6%80%A7%E6%95%88%E6%9E%9C">\u6FC0\u6D3B\u6027\u6548\u679C</a>\uFF1A\u5BF9\u4E0B\u5BB6\u65BD\u52A0<strong>\u7F34\u68B0\u5B50\u6548\u679C</strong>\u3002</p><p>\u7F34\u68B0\u5B50\u6548\u679C\uFF1A\u73A9\u5BB6\u5224\u5B9A\u9636\u6BB5\u9009\u62E9\u63A5\u53D7\u4E0E\u4E0D\u63A5\u53D7\u7F34\u68B0\u6548\u679C\uFF0C\uFF08\u4E0D\u7BA1\u505A\u4F55\u9009\u62E9\u90FD\uFF09\u8DF3\u8FC7\u4ED6\u7684\u56DE\u5408\u3002\u6548\u679C\u7ED3\u675F\u3002</p><ul><li>\u63A5\u53D7\u7F34\u68B0\uFF1A\u5F03\u4E24\u5F20\u529F\u80FD\u724C\u3002</li><li>\u4E0D\u63A5\u53D7\u7F34\u68B0\uFF1A\u64784\u5F20\u724C\u3002</li></ul><h3 id="\u624B\u69B4\u5F39" tabindex="-1"><a class="header-anchor" href="#\u624B\u69B4\u5F39" aria-hidden="true">#</a> \u624B\u69B4\u5F39</h3><p><a href="#aoe%E6%95%88%E6%9E%9C">AOE\u6548\u679C</a>\uFF1A\u6307\u5B9A\u56DB\u79CD\u57FA\u7840\u989C\u8272\u4E4B\u4E00\u5E76\u5C06\u624B\u69B4\u5F39\u4F20\u7ED9\u4E0B\u5BB6\u3002\u63A5\u53D7\u8005\u9700\u6253\u51FA\u8BE5\u989C\u8272\u7684\u724C\u5E76\u6307\u5B9A\u989C\u8272\u540E\u7EE7\u7EED\u4F20\u9012\u7ED9\u4E0B\u5BB6\u3002\u5426\u5219\uFF0C\u5C06\u624B\u724C\u5168\u5F03\uFF0C\u7136\u540E\u6478\u4E0E\u521D\u59CB\u624B\u724C\u6570\u76F8\u7B49\u7684\u724C\uFF0C\u624B\u69B4\u5F39\u6548\u679C\u7ED3\u675F\u3002\u8FC7\u7A0B\u4E2D\u6253\u51FA\u7684\u724C\u5747\u8BA1\u5165<code>last</code>\u3002</p><h3 id="\u7D27\u7B8D\u5492" tabindex="-1"><a class="header-anchor" href="#\u7D27\u7B8D\u5492" aria-hidden="true">#</a> \u7D27\u7B8D\u5492</h3><p><a href="#%E6%BF%80%E6%B4%BB%E6%80%A7%E6%95%88%E6%9E%9C">\u6FC0\u6D3B\u6027\u6548\u679C</a>\uFF1A\u5BF9\u4EFB\u610F\u73A9\u5BB6\u65BD\u52A0<strong>\u7D27\u7B8D\u5492\u5B50\u6548\u679C</strong>\u3002</p><p>\u7D27\u7B8D\u5492\u5B50\u6548\u679C\uFF1A\u5C5E\u4E8E<a href="#%E6%8C%81%E7%BB%AD%E6%80%A7%E6%95%88%E6%9E%9C">\u6301\u7EED\u6027\u6548\u679C</a>\uFF0C\u62E5\u6709\u53D8\u91CF\uFF1A<code>\u6709\u6548\u624B\u724C\u6570</code>\u3002\u5BF9\u65E0\u6548\u679C\u7684\u73A9\u5BB6\u800C\u8A00\uFF0C<code>\u6709\u6548\u624B\u724C\u6570</code>\u4E0E\u5F53\u524D\u624B\u724C\u6570\u76F8\u7B49\u3002\u65BD\u52A0\u6548\u679C\u77AC\u95F4\uFF0C\u6709\u6548\u624B\u724C\u6570\u51CF\u534A\uFF08\u5411\u4E0A\u53D6\u6574\uFF09\u3002\u7D27\u7B8D\u5492\u6548\u679C\u53EF\u53E0\u52A0\u3002</p><p>\u73A9\u5BB6\u5728\u4EFB\u4F55\u60C5\u51B5\u4E0B\u4E0D\u8BB8\u4ECE\u724C\u5806\u4E2D\u6478\u724C\uFF08\u4E0D\u5F71\u54CD\u4ECE\u5176\u4ED6\u73A9\u5BB6\u5904\u83B7\u5F97\u724C\uFF09\u3002</p><p>\u89E3\u9664\u6761\u4EF6\uFF1A\u624B\u724C\u6570\u4E0D\u5927\u4E8E<code>\u6709\u6548\u624B\u724C\u6570</code>\u3002\u89E3\u9664\u540E\u672C\u6B21<code>\u6709\u6548\u624B\u724C\u6570</code>\u4F5C\u5E9F\u3002</p><h3 id="\u590D\u6D3B" tabindex="-1"><a class="header-anchor" href="#\u590D\u6D3B" aria-hidden="true">#</a> \u590D\u6D3B</h3><p><a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF1A\u53EF\u9009\u62E9\u5BF9\u81EA\u5DF1\u7528\u6216\u5BF9\u5DF2\u4E0B\u573A\u73A9\u5BB6\u7528\u3002</p><ul><li>\u5BF9\u81EA\u5DF1\u7528\uFF1A\u6478\u4E09\u5F20\u724C\u3002</li><li>\u5BF9\u5DF2\u4E0B\u573A\u73A9\u5BB6\u7528\uFF08\u4E00\u5C40\u4EC5\u9650\u4E00\u6B21\uFF09\uFF1A\u4EE4\u4E4B\u91CD\u65B0\u56DE\u5230\u573A\u4E0A\uFF0C\u6478\u4E00\u5F20\u724C\uFF0C\u83B7\u5F97<a href="#%E7%9C%A9%E6%99%95%E6%95%88%E6%9E%9C">\u7729\u6655\u6548\u679C</a>\u3002</li></ul><h3 id="c4" tabindex="-1"><a class="header-anchor" href="#c4" aria-hidden="true">#</a> C4</h3><p><a href="#aoe%E6%95%88%E6%9E%9C">AOE\u6548\u679C</a>\uFF1A\u7531\u53D1\u8D77\u8005\u5F00\u59CB\uFF0C\u51FA\u4E00\u5F20\u6570\u5B57\u724C\u4F7FC4\u88AB\u5411\u4E0B\u4F20\u9012x\u5BB6\uFF0Cx\u4E3A\u6B64\u6570\u5B57\u724C\u7684\u5927\u5C0F\u3002\u7136\u540E\u8DF3\u8F6C\u5230\u63A5\u5230C4\u7684\u73A9\u5BB6\u7684\u56DE\u5408\uFF0C\u91CD\u590D\u8BE5\u8FC7\u7A0B\u3002\u82E5\u67D0\u4F4D\u73A9\u5BB6\u65E0\u6CD5\u6253\u51FA\u6570\u5B57\u724C\uFF0C\u5219C4\u7206\u70B8\uFF0C\u4F7F\u8BE5\u73A9\u5BB6\u5F03\u6389\u6240\u6709\u624B\u724C\u5E76\u91CD\u65B0\u6478\u7B49\u4E8E\u521D\u59CB\u624B\u724C\u6570\u7684\u724C\uFF0C\u5E76\u7531\u53D1\u8D77\u8005\u7684\u4E0B\u5BB6\u5F00\u59CB\u65B0\u7684\u56DE\u5408\u3002\uFF08\u82E5\u88AB\u70B8\u7684\u5C31\u662F\u53D1\u8D77\u8005\u7684\u4E0B\u5BB6\uFF0C\u5219\u8DF3\u8FC7\u6B64\u73A9\u5BB6\uFF09\u8FC7\u7A0B\u4E2D\u7684\u6570\u5B57\u724C\u5C06\u66FF\u6362<code>last</code>\u3002</p><h3 id="\u62AC\u6760" tabindex="-1"><a class="header-anchor" href="#\u62AC\u6760" aria-hidden="true">#</a> \u62AC\u6760</h3><p><a href="#aoe%E6%95%88%E6%9E%9C">AOE\u6548\u679C</a>\uFF1A\u5BF9\u81EA\u5DF1\u65BD\u52A0<strong>\u62AC\u6760\u5B50\u6548\u679C</strong>\u5E76\u7ACB\u523B\u5224\u5B9A\u3002</p><p>\u62AC\u6760\u5B50\u6548\u679C\uFF1A\u5C5E\u4E8E<a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF0C\u62E5\u6709\u53D8\u91CF\uFF1A<code>x</code>\uFF0C\u521D\u59CB\u503C\u4E3A0\u3002</p><p>\u6253\u51FA\u4E0D\u5C0F\u4E8E<code>x</code>\u7684\u6570\u5B57\u724C\u5E76\u4F20\u7ED9\u4E0B\u4E00\u5BB6\uFF0C\u5E76\u628A\u6570\u5B57\u8D4B\u7ED9<code>x</code>\u3002\u82E5\u6253\u4E0D\u51FA\u5219\u6548\u679C\u7ED3\u675F\uFF0C\u64784\u5F20\u724C\uFF0C\u7531\u53D1\u8D77\u8005\u7684\u4E0B\u5BB6\u5F00\u59CB\u65B0\u7684\u56DE\u5408\u3002\u8FC7\u7A0B\u4E2D\u7684\u6570\u5B57\u724C\u5C06\u66FF\u6362<code>last</code>\u3002</p><h3 id="\u5956\u52B1" tabindex="-1"><a class="header-anchor" href="#\u5956\u52B1" aria-hidden="true">#</a> \u5956\u52B1</h3><p><a href="#%E5%8D%B3%E6%97%B6%E6%80%A7%E6%95%88%E6%9E%9C">\u5373\u65F6\u6027\u6548\u679C</a>\uFF1A<strong>\u5FC5\u9700</strong>\u6253\u51FA\u6240\u6709\u4E0E\u5956\u52B1\u724C\u989C\u8272\u76F8\u540C\u7684\u724C\uFF0C\u7ACB\u523B\u83B7\u5F97<a href="#%E7%9C%A9%E6%99%95%E6%95%88%E6%9E%9C">\u7729\u6655\u6548\u679C</a>\u4E0E<a href="#%E8%99%9A%E5%BC%B1%E6%95%88%E6%9E%9C">\u865A\u5F31\u6548\u679C</a>\uFF0C\u5E76<strong>\u53EF\u9009\u62E9</strong>\u662F\u5426\u6253\u51FA\u4E00\u5F20\u4EFB\u610F\u989C\u8272\u7684<a href="#%E7%A5%9E%E6%89%8B">\u795E\u624B</a>\u3002\uFF08\u82E5<a href="#%E7%A5%9E%E6%89%8B">\u795E\u624B</a>\u4E0E\u5956\u52B1\u540C\u8272\u88AB\u5F3A\u5236\u6253\u51FA\uFF0C\u4E5F\u53EF\u9009\u62E9\u88AB\u7B97\u4F5C\u6253\u51FA\uFF09</p><ul><li>\u82E5\u9009\u62E9\u6253\u51FA<a href="#%E7%A5%9E%E6%89%8B">\u795E\u624B</a>\uFF0C\u4F60<strong>\u53EF\u4EE5</strong>\u5C06\u521A\u6253\u51FA\u7684\u6240\u6709<code>\u4E0E\u5956\u52B1\u724C\u989C\u8272\u76F8\u540C\u7684\u724C</code>\u76D6\u4E0A\uFF0C\u5F3A\u5236\u8BA9\u9664\u4F60\u4EE5\u5916\u7684\u6BCF\u4F4D\u8F6E\u6D41\u62BD\u4E00\u5F20\u3002\uFF08\u62BD\u5B8C\u5373\u505C\uFF0C\u62BD\u4E0D\u5B8C\u9700\u8981\u8F6E\u6D41\u5230\u62BD\u5B8C\u4E3A\u6B62\uFF09</li></ul><h3 id="\u5DF2\u5F03\u7528\u529F\u80FD\u724C" tabindex="-1"><a class="header-anchor" href="#\u5DF2\u5F03\u7528\u529F\u80FD\u724C" aria-hidden="true">#</a> \u5DF2\u5F03\u7528\u529F\u80FD\u724C</h3><p>\u6B64\u5904\u5B58\u653E\u4E00\u4E9B\u66FE\u7ECF\u6784\u601D\u8FC7\u4F46\u56E0\u4E3A\u5404\u79CD\u539F\u56E0\u88AB\u5F03\u7528\u7684\u529F\u80FD\u724C\u3002\u8FD9\u4E9B\u529F\u80FD\u724C\u7684\u89E3\u91CA\u4E0D\u5177\u6709\u4E25\u8C28\u6027\u3002</p><h4 id="\u7EC4\u5408\u724C" tabindex="-1"><a class="header-anchor" href="#\u7EC4\u5408\u724C" aria-hidden="true">#</a> \u7EC4\u5408\u724C</h4><p>\u5355\u72EC\u6253\u51FA\u4E3A\u767D\u724C\u6548\u679C\uFF0C\u53EF\u4EE5\u9009\u62E9\u540C\u65F6\u6253\u51FA\u201C\u7EC4\u5408\u724C\u4E0A\u5199\u7684\u6570\u5B57\u7EC4\u5408\uFF0C\u6216\u80054\u5F20\u540C\u6570\u5B57\u70B8\u5F39\u201D\u3002</p><h4 id="\u5929\u5F03\u4E4B\u5B50" tabindex="-1"><a class="header-anchor" href="#\u5929\u5F03\u4E4B\u5B50" aria-hidden="true">#</a> \u5929\u5F03\u4E4B\u5B50</h4><p>\u51FA\u6B64\u5F20\u724C\uFF0C\u5FC5\u987B\u4E0D\u65AD\u6478\u724C\u76F4\u81F3\u6478\u51FA\u6570\u5B57\u724C\u6216\u8005\u529F\u80FD\u724C\uFF08\u6478\u724C\u524D\u81EA\u9009\uFF09\u3002</p><h4 id="\u8DF3\u8F6C" tabindex="-1"><a class="header-anchor" href="#\u8DF3\u8F6C" aria-hidden="true">#</a> \u8DF3\u8F6C</h4><p>\u5C06\u5F53\u524D\u56DE\u5408\uFF08\u5305\u62EC\u5F53\u524D\u6548\u679C\uFF0C\u76F8\u5F53\u4E8Epass\uFF09\u8DF3\u8F6C\u5230\u6307\u5B9A\u73A9\u5BB6\uFF0C\u4E0D\u6539\u53D8\u987A\u5E8F\u4E0E\u5F53\u524D\u724C\u3002</p><h4 id="\u8D4C\u602A" tabindex="-1"><a class="header-anchor" href="#\u8D4C\u602A" aria-hidden="true">#</a> \u8D4C\u602A</h4><p>\u53CC\u65B9\u5404\u51FA4\u5F20\u6570\u5B57\u724C\uFF08\u82E5\u4E0D\u591F\u5219\u8865\u81F34\u5F20\uFF09\uFF0C\u6DF7\u5408\u540E\uFF0C\u4EE50\u4F5C\u4E3A\u521D\u59CB\u6570\u5B57\uFF0C\u76F8\u4E92\u4E00\u4EBA\u53D6\u4E00\u5F20\u6309\u81EA\u5B9A\u4E49\u987A\u5E8F\u8FDB\u884C\u52A0\u4E58\u51CF\u9664\uFF0C\u6700\u540E\u5C06\u7ED3\u679C\u62FF\u6765\u6BD4\u5927\u5C0F\uFF0C\u8D62\u5F97\u53EF\u9009\u62E9\u81EA\u5DF1\u5F032\u5F20\u6216\u5BF9\u624B\u64784\u5F20\u3002\u82E5\u51FA\u73B0\u9664\u4EE5\u96F6\u5219\u6309\u7167\u9664\u4EE5\u65E0\u7A77\u5C0F\u7684\u6B63\u6570\u8BA1\u7B97\u3002</p><h3 id="\u7CBE\u7B80\u89C4\u5219" tabindex="-1"><a class="header-anchor" href="#\u7CBE\u7B80\u89C4\u5219" aria-hidden="true">#</a> \u7CBE\u7B80\u89C4\u5219</h3><p>\u6B64\u7CBE\u7B80\u89C4\u5219\u9ED8\u8BA4\u7EE7\u627F\u81EAUNO\u57FA\u7840\u89C4\u5219\u3002</p><p>\u6548\u679C\u4F18\u5148\u7EA7\uFF1A\u7981 &gt; \u795E\u624B &gt; \u5939\u5B50 &gt; \u70B8\u5F39\uFF0C\u51B3\u6597\uFF0C\u7F34\u68B0\uFF0C\u62AC\u6760\uFF0Cc4\u7B49\u4E00\u822C\u529F\u80FD\u724C &gt; \u53CD\u5F39\uFF0Cpass\uFF0C\u8DF3\u8F6C &gt; \u4F20\u9012\uFF0C\u52A0\u724C\u3002</p><p>\u975E\u201C\u6539\u53D8\u989C\u8272\u7684\u724C\uFF08\u6539\u8272\uFF0C+4\uFF09\u201D\u4E0D\u6539\u53D8\u5F53\u524D\u724C\u3002\u89C6\u4E3A\u6253\u51FA\u7684\u724C\u4F1A\u6210\u4E3A\u5F53\u524D\u724C\u3002</p><p>\u73A9\u5BB6\u80DC\u5229\u5F53\u4E14\u4EC5\u5F53\u65E0\u624B\u724C\u4E14\u8EAB\u4E0A\u65E0\u4EFB\u4F55\u6548\u679C\u3002C4\uFF0C\u62AC\u6760\u7B49\u89C6\u4E3A\u5BF9\u5168\u5C40\u73A9\u5BB6\u6DFB\u52A0\u6548\u679C\u3002</p><p>\u5404\u79CD\u529F\u80FD\u724C\u7684\u4F5C\u7528\uFF1A</p><h4 id="\u53CD\u5F39\u724C" tabindex="-1"><a class="header-anchor" href="#\u53CD\u5F39\u724C" aria-hidden="true">#</a> \u53CD\u5F39\u724C</h4><p>\u6536\u5230\u7684\u6548\u679C\u53CD\u5F39\uFF0C\u4E14\u53CD\u8F6C\u51FA\u724C\u987A\u5E8F\u3002\u82E5\u65E0\u6548\u679C\u53EF\u5F53\u4F5C\u9006\u8F6C\u6253\u3002</p><h4 id="pass\u724C" tabindex="-1"><a class="header-anchor" href="#pass\u724C" aria-hidden="true">#</a> pass\u724C</h4><p>\u6548\u679C\u4F20\u7ED9\u4E0B\u4E00\u5BB6\uFF0C\u82E5\u65E0\u6548\u679C\u53EF\u5F53\u4F5C\u767D\u724C\u6253\u3002</p><h4 id="\u51B3\u6597\u724C" tabindex="-1"><a class="header-anchor" href="#\u51B3\u6597\u724C" aria-hidden="true">#</a> \u51B3\u6597\u724C</h4><p>\u4EFB\u9009\u4E00\u4E2A\u4EBA\u5355\u6311\u5206\u522B\u662F\u62FC\u5927\u5C0F\u548C\u731C\u989C\u8272\uFF0C\u8D62\u7684\u4EBA\u6254\u4E24\u5F20\u724C\uFF0C\u8F93\u7684\u4EBA\u52A0\u56DB\u5F20\u724C\uFF0C\u5E73\u5C40\u7B97\u7686\u8F93\u3002\u6570\u5B57\u51B3\u6597\u4E3A\u4E24\u4EBA\u5404\u7FFB\u4E00\u5F20\u724C\u62FC\u70B9\uFF1B\u989C\u8272\u51B3\u6597\u4E3A\u53D1\u8D77\u4EBA\u9009\u62E95\u4E2A\u989C\u8272\uFF08\u5305\u62EC\u9ED1\u8272\uFF09\u4E2D\u7684\u4E00\u4E2A\uFF0C\u63A5\u53D7\u8005\u9009\u62E9\u4E0D\u540C\u989C\u8272\uFF0C\u7136\u540E\u53D1\u8D77\u4EBA\u7FFB\u8D77\u724C\u9876\u4E00\u5F20\u724C\u5E76\u516C\u793A\uFF0C\u731C\u5BF9\u4E3A\u80DC\u5229\u3002</p><h4 id="\u65E0\u9650\u724C" tabindex="-1"><a class="header-anchor" href="#\u65E0\u9650\u724C" aria-hidden="true">#</a> \u65E0\u9650\u724C</h4><p>\u53EF\u4EE5\u5145\u5F53\u4EFB\u610F\u6570\u5B57\u3002\u4E0D\u53EF\u7528\u4E8E\u8D4C\u602A\u4E2D\u3002</p><h4 id="\u5929\u9009\u4E4B\u5B50-1" tabindex="-1"><a class="header-anchor" href="#\u5929\u9009\u4E4B\u5B50-1" aria-hidden="true">#</a> \u5929\u9009\u4E4B\u5B50</h4><p>\u53EA\u4FDD\u7559\u4E00\u5F20\u6570\u5B57\u724C\uFF0C\u5F03\u6389\u5176\u4ED6\u6240\u6709\u724C\uFF08\u82E5\u65E0\u6570\u5B57\u5219\u76F4\u63A5\u80DC\u5229\uFF09\u3002</p><h4 id="\u4F20\u9012\u724C" tabindex="-1"><a class="header-anchor" href="#\u4F20\u9012\u724C" aria-hidden="true">#</a> \u4F20\u9012\u724C</h4><p>\u5728\u4E0A\u4E00\u5F20\u724C\u540C\u65F6\u6EE1\u8DB3\u989C\u8272\u6761\u4EF6\u4E0E\u6570\u5B57\u6761\u4EF6\u65F6\u6253\u51FA\uFF0C\u6216\u5728\u4E0A\u4E00\u5F20\u724C\u4E3A\u540C\u7C7B\u578B\u724C\u65F6\u6253\u51FA\u3002\u53EF\u4EE5\u4EFB\u90090-2\u5F20\u724C\u4F20\u9012\u7ED9\u4E0B\u5BB6\u3002\u4F20\u9012\u724C\u53EF\u53E0\u52A0\uFF0C\u4F46\u4F20\u9012\u8FC7\u7A0B\u4E2D\u4E0D\u53EF\u770B\u724C\u3002\u5F53\u6709\u4EBA\u9009\u62E9\u63A5\u6536\u4F20\u9012\u540E\uFF0C\u5219\u4ED6\u7684\u8FD9\u4E00\u9636\u6BB5\u4E0D\u53EF\u518D\u6253\u51FA\u4F20\u9012\u724C\uFF08\u5373\u4F7F\u540C\u7C7B\u578B\uFF09\u3002</p><h4 id="\u795E\u624B-1" tabindex="-1"><a class="header-anchor" href="#\u795E\u624B-1" aria-hidden="true">#</a> \u795E\u624B</h4><p>\u4E0E\u4E0B\u5BB6\u6362\u724C\uFF0C\u5177\u6709\u6781\u9AD8\u4F18\u5148\u7EA7\u3002</p><h4 id="\u70B8\u5F39-1" tabindex="-1"><a class="header-anchor" href="#\u70B8\u5F39-1" aria-hidden="true">#</a> \u70B8\u5F39</h4><p>\u4EE5\u81EA\u5DF1\u4E3A\u4E2D\u5FC3\u5411\u4E24\u4FA7\u6269\u6563\uFF0C\u81EA\u5DF1\u52A0\u5168\u573A\u4EBA\u6570\u7684\u724C\uFF0C\u6BCF\u6269\u6563\u4E00\u4E2A\u4EBA\u52A0\u724C\u6570\u51CF\u4E00\u3002</p><h4 id="\u7F34\u68B0-1" tabindex="-1"><a class="header-anchor" href="#\u7F34\u68B0-1" aria-hidden="true">#</a> \u7F34\u68B0</h4><p>\u4E0B\u5BB6\u9009\u62E9\uFF1A\u5F03\u4E24\u5F20\u529F\u80FD\u724C\uFF0C\u6216\u8005\u52A0\u56DB\u5F20\u724C\u3002\u5E76\u8DF3\u8FC7\u81EA\u5DF1\u7684\u8FD9\u4E2A\u56DE\u5408\u3002</p><h4 id="\u5939\u5B50-1" tabindex="-1"><a class="header-anchor" href="#\u5939\u5B50-1" aria-hidden="true">#</a> \u5939\u5B50</h4><p>\u62BD\u4E0B\u5BB6\u4E24\u5F20\u724C\uFF0C\u82E5\u4E0D\u8DB3\u4E24\u5F20\u5219\u62BD\u53D6\u5168\u90E8\u3002</p><h4 id="\u624B\u69B4\u5F39-1" tabindex="-1"><a class="header-anchor" href="#\u624B\u69B4\u5F39-1" aria-hidden="true">#</a> \u624B\u69B4\u5F39</h4><p>\u6307\u5B9A\u4E00\u4E2A\u989C\u8272\uFF08\u4EC5\u56DB\u79CD\u57FA\u7840\u989C\u8272\uFF09\u5E76\u5C06\u624B\u69B4\u5F39\u4F20\u7ED9\u4E0B\u5BB6\u3002\u4E0B\u5BB6\u9700\u6253\u51FA\u8BE5\u989C\u8272\u7684\u724C\u5E76\u6307\u5B9A\u989C\u8272\u540E\u4F20\u7ED9\u4E0B\u5BB6\u3002\u5426\u5219\uFF0C\u5C06\u624B\u724C\u4E0E\u624B\u69B4\u5F39\u5168\u5F03\uFF0C\u7136\u540E\u6478\u4E0E\u521D\u59CB\u624B\u724C\u6570\u76F8\u7B49\u7684\u724C\u3002</p><h4 id="\u7D27\u7B8D\u5492-1" tabindex="-1"><a class="header-anchor" href="#\u7D27\u7B8D\u5492-1" aria-hidden="true">#</a> \u7D27\u7B8D\u5492</h4><p>\u5BF9\u4EFB\u610F\u73A9\u5BB6\u4F7F\u7528\uFF0C\u8BE5\u73A9\u5BB6\u5728\u4EFB\u4F55\u60C5\u51B5\u4E0D\u8BB8\u4ECE\u724C\u5806\u4E2D\u6478\u724C\uFF08\u4E0D\u5F71\u54CD\u4ECE\u5176\u4ED6\u73A9\u5BB6\u5904\u83B7\u5F97\u724C\uFF09\uFF0C\u76F4\u5230\u624B\u724C\u6570\u964D\u81F3\u4E00\u534A\uFF08\u5411\u4E0A\u53D6\u6574\uFF09\u53CA\u4EE5\u4E0B\u540E\uFF0C\u89E3\u9664\u7D27\u7B8D\u5492\u6548\u679C\u3002\u7D27\u7B8D\u5492\u6548\u679C\u53EF\u53E0\u52A0\u3002</p><h4 id="\u590D\u6D3B-1" tabindex="-1"><a class="header-anchor" href="#\u590D\u6D3B-1" aria-hidden="true">#</a> \u590D\u6D3B</h4><p>\u5BF9\u81EA\u5DF1\u7528\uFF1A\u81EA\u5DF1\u6478\u4E09\u5F20\u724C\u3002\u5BF9\u5DF2\u4E0B\u573A\u73A9\u5BB6\u7528\uFF08\u4E00\u5C40\u53EA\u80FD\u7528\u4E00\u6B21\uFF09\uFF1A\u91CD\u65B0\u56DE\u5230\u573A\u4E0A\u5E76\u6478\u4E00\u5F20\u724C\uFF1B\u590D\u6D3B\u540E\u8DF3\u8FC7\u81EA\u5DF1\u7684\u7B2C\u4E00\u4E2A\u56DE\u5408\u3002</p><h4 id="c4-1" tabindex="-1"><a class="header-anchor" href="#c4-1" aria-hidden="true">#</a> C4</h4><p>\u51FA\u6B64\u724C\u7684\u4EBA\u5F00\u59CB\uFF0C\u51FA\u4E00\u5F20\u6570\u5B57\u724C\u4F7Fc4\u88AB\u5411\u4E0B\u4F20\u9012x\u5BB6\uFF0Cx\u4E3A\u6B64\u6570\u5B57\u724C\u7684\u5927\u5C0F\u3002\u7136\u540E\u8DF3\u8F6C\u5230\u63A5\u5230c4\u7684\u73A9\u5BB6\u7684\u56DE\u5408\u91CD\u590D\u8BE5\u8FC7\u7A0B\u3002\u82E5\u65E0\u6CD5\u6253\u51FA\u6570\u5B57\u724C\uFF0C\u5219\u76F4\u63A5\u7206\u70B8\uFF0C\u4F7F\u62FF\u7740c4\u7684\u73A9\u5BB6\u5F03\u6389\u6240\u6709\u624B\u724C\u5E76\u91CD\u65B0\u6478\u521D\u59CB\u724C\uFF0C\u5E76\u7531\u51FA\u724C\u8005\u7684\u4E0B\u5BB6\u5F00\u59CB\u65B0\u7684\u56DE\u5408\u3002\u8FC7\u7A0B\u4E2D\u7684\u6570\u5B57\u724C\u89C6\u4E3A\u6253\u51FA\u3002</p><h4 id="\u62AC\u6760-1" tabindex="-1"><a class="header-anchor" href="#\u62AC\u6760-1" aria-hidden="true">#</a> \u62AC\u6760</h4><p>\u7531\u51FA\u724C\u8005\u5F00\u59CB\u51FA\u6570\u5B57\u724C\uFF0C\u5E76\u4F20\u7ED9\u4E0B\u4E00\u5BB6\uFF0C\u4E0B\u4E00\u5BB6\u9700\u8981\u6253\u51FA\u5927\u4E8E\u7B49\u4E8E\u4E0A\u5F20\u6570\u5B57\u7684\u6570\u5B57\u724C\uFF0C\u82E5\u6253\u4E0D\u51FA\u5219\u62AC\u6760\u7ED3\u675F\uFF0C\u5931\u8D25\u8005\u64784\u5F20\uFF0C\u7531\u51FA\u724C\u8005\u7684\u4E0B\u5BB6\u5F00\u59CB\u65B0\u7684\u56DE\u5408\u3002\u8FC7\u7A0B\u4E2D\u7684\u6570\u5B57\u724C\u89C6\u4E3A\u6253\u51FA\u3002</p>',149),i=[h];function n(c,s){return a(),t("div",null,i)}var l=e(r,[["render",n],["__file","other_games.html.vue"]]);export{l as default};
